/**
 * Capitalises the first letter of each word in a string.
 *
 * @param input - The string to be transformed.
 * @returns The title‑cased version of the input string.
 *
 * Example:
 *   titleCase("hello world") // "Hello World"
 */
export function titleCase(input: string): string {
    if (!input) {
        return "";
    }

    // Convert the whole string to lower case first to ensure consistent casing,
    // then split on whitespace, capitalize each word, and re‑join.
    return input
        .toLowerCase()
        .split(/\s+/)                     // split on one or more whitespace characters
        .filter(word => word.length > 0) // remove any empty entries caused by leading/trailing spaces
        .map(word => word[0].toUpperCase() + word.slice(1))
        .join(" ");
}
