// Placeholder implementation for a simple health component in Unity.

using UnityEngine;

[DisallowMultipleComponent]
public class Health : MonoBehaviour
{
    [Header("Health Settings")]
    [SerializeField] private int maxHealth = 100;
    [SerializeField] private bool startAtMaxHealth = true;

    public int MaxHealth => maxHealth;
    public int CurrentHealth { get; private set; }

    public delegate void HealthChanged(int currentHealth, int maxHealth);
    public event HealthChanged OnHealthChanged;

    public delegate void Death();
    public event Death OnDeath;

    private void Awake()
    {
        if (startAtMaxHealth)
        {
            CurrentHealth = maxHealth;
        }
        else
        {
            CurrentHealth = Mathf.Clamp(CurrentHealth, 0, maxHealth);
        }

        NotifyHealthChanged();
    }

    /// <summary>
    /// Apply damage to this entity.
    /// </summary>
    /// <param name="damage">Amount of damage to apply. Must be non‑negative.</param>
    public void TakeDamage(int damage)
    {
        if (damage < 0) return;

        CurrentHealth = Mathf.Max(CurrentHealth - damage, 0);
        NotifyHealthChanged();

        if (CurrentHealth == 0)
        {
            Die();
        }
    }

    /// <summary>
    /// Heal this entity.
    /// </summary>
    /// <param name="amount">Amount of health to restore. Must be non‑negative.</param>
    public void Heal(int amount)
    {
        if (amount < 0) return;

        CurrentHealth = Mathf.Min(CurrentHealth + amount, maxHealth);
        NotifyHealthChanged();
    }

    /// <summary>
    /// Instantly set health to a specific value.
    /// </summary>
    /// <param name="value">New health value. Clamped between 0 and maxHealth.</param>
    public void SetHealth(int value)
    {
        CurrentHealth = Mathf.Clamp(value, 0, maxHealth);
        NotifyHealthChanged();

        if (CurrentHealth == 0)
        {
            Die();
        }
    }

    private void Die()
    {
        OnDeath?.Invoke();
        // Placeholder: you could add destruction, animation, etc. here.
    }

    private void NotifyHealthChanged()
    {
        OnHealthChanged?.Invoke(CurrentHealth, maxHealth);
    }

#if UNITY_EDITOR
    private void OnValidate()
    {
        maxHealth = Mathf.Max(1, maxHealth);
        if (startAtMaxHealth)
        {
            CurrentHealth = maxHealth;
        }
        else
        {
            CurrentHealth = Mathf.Clamp(CurrentHealth, 0, maxHealth);
        }
    }
#endif
}
