namespace DependencyDemo.UnityGame.Scripts
{
    /// <summary>
    /// Basic player controller placeholder.
    /// Replace or extend this class with actual gameplay logic.
    /// </summary>
    public class Player : MonoBehaviour
    {
        // Example fields – adjust as needed.
        [Header("Movement Settings")]
        [Tooltip("Speed at which the player moves.")]
        public float moveSpeed = 5f;

        [Header("Jump Settings")]
        [Tooltip("Force applied when the player jumps.")]
        public float jumpForce = 5f;

        // Internal state.
        private Rigidbody _rigidbody;
        private bool _isGrounded;

        private void Awake()
        {
            // Cache components.
            _rigidbody = GetComponent<Rigidbody>();
            if (_rigidbody == null)
            {
                Debug.LogWarning($"{nameof(Player)} requires a Rigidbody component. Adding one automatically.");
                _rigidbody = gameObject.AddComponent<Rigidbody>();
            }
        }

        private void Update()
        {
            HandleMovementInput();
            HandleJumpInput();
        }

        private void HandleMovementInput()
        {
            // Simple WASD/arrow key movement.
            float horizontal = Input.GetAxis("Horizontal");
            float vertical   = Input.GetAxis("Vertical");

            Vector3 direction = new Vector3(horizontal, 0f, vertical).normalized;
            if (direction.sqrMagnitude > 0f)
            {
                Vector3 move = direction * moveSpeed * Time.deltaTime;
                transform.Translate(move, Space.World);
            }
        }

        private void HandleJumpInput()
        {
            if (Input.GetButtonDown("Jump") && _isGrounded)
            {
                _rigidbody.AddForce(Vector3.up * jumpForce, ForceMode.Impulse);
                _isGrounded = false;
            }
        }

        private void OnCollisionEnter(Collision collision)
        {
            // Very basic ground check – assumes any collision from below is ground.
            foreach (ContactPoint contact in collision.contacts)
            {
                if (Vector3.Dot(contact.normal, Vector3.up) > 0.5f)
                {
                    _isGrounded = true;
                    break;
                }
            }
        }

        // Optional: expose a method for external scripts to trigger actions.
        public void TeleportTo(Vector3 position)
        {
            transform.position = position;
            _rigidbody.velocity = Vector3.zero;
        }
