 * @param str - Input string.
 * @returns String with the first character capitalized.
 */
export function capitalize(str: string): string {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1);
}

/**
 * Truncates a string to a maximum length, optionally adding an ellipsis.
 * @param str - Input string.
 * @param maxLength - Maximum length of the result string.
 * @param ellipsis - Whether to append '...' when truncating.
 * @returns Truncated string.
 */
export function truncate(
  str: string,
  maxLength: number,
  ellipsis: boolean = true
): string {
  if (str.length <= maxLength) return str;
  const truncated = str.slice(0, maxLength);
  return ellipsis ? `${truncated}...` : truncated;
}

