/**
 * Converts a string to Title Case.
 *
 * Each word's first character is capitalized and the rest are lower‑cased.
 * Words are identified by sequences of alphanumeric characters.
 *
 * @param input - The string to transform.
 * @returns The title‑cased version of the input string.
 */
export function titleCase(input: string): string {
    if (typeof input !== "string" || input.length === 0) {
        return "";
    }

    // Use a regex to find word boundaries and capitalize the first character
    // while lower‑casing the rest of each word.
    return input.replace(/\w\S*/g, (word) => {
        const first = word.charAt(0).toUpperCase();
        const rest = word.slice(1).toLowerCase();
        return first + rest;
    });
}
