/**
 * Title‑cases a given string.
 *
 * Each word's first character is converted to upper case and the rest to lower case.
 * Words are considered to be sequences separated by whitespace characters.
 *
 * @param input - The string to be title‑cased.
 * @returns The title‑cased version of the input string.
 *
 * Example:
 *   titleCase("hello world") // => "Hello World"
 *   titleCase("MULTI word STRING") // => "Multi Word String"
 */
export function titleCase(input: string): string {
    if (!input) {
        return "";
    }

    // Split on any whitespace (space, tab, newline, etc.)
    const words = input.split(/\s+/);

    const transformed = words.map(word => {
        if (word.length === 0) {
            return "";
        }
        const first = word[0].toUpperCase();
        const rest = word.slice(1).toLowerCase();
        return first + rest;
    });

    // Preserve the original spacing pattern (single spaces between words)
    // If you need to keep exact original whitespace, a more complex approach is required.
    return transformed.join(" ");
}
