// script.js – form validation for login and registration pages

// Utility: simple email regex
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Show an error message for a specific input element
function showError(input, message) {
  let errorElem = input.parentElement.querySelector('.error');
  if (!errorElem) {
    errorElem = document.createElement('div');
    errorElem.className = 'error';
    errorElem.style.color = 'red';
    errorElem.style.fontSize = '0.9em';
    input.parentElement.appendChild(errorElem);
  }
  errorElem.textContent = message;
  input.classList.add('invalid');
}

// Clear the error message for a specific input element
function clearError(input) {
  const errorElem = input.parentElement.querySelector('.error');
  if (errorElem) {
    errorElem.textContent = '';
  }
  input.classList.remove('invalid');
}

// Validate login form fields
function validateLoginForm(form) {
  let valid = true;

  const emailInput = form.querySelector('input[name="email"]');
  const passwordInput = form.querySelector('input[name="password"]');

  // Email validation
  if (!emailInput.value.trim()) {
    showError(emailInput, 'Email is required.');
    valid = false;
  } else if (!emailRegex.test(emailInput.value.trim())) {
    showError(emailInput, 'Please enter a valid email address.');
    valid = false;
  } else {
    clearError(emailInput);
  }

  // Password validation
  if (!passwordInput.value) {
    showError(passwordInput, 'Password is required.');
    valid = false;
  } else if (passwordInput.value.length < 6) {
    showError(passwordInput, 'Password must be at least 6 characters.');
    valid = false;
  } else {
    clearError(passwordInput);
  }

  return valid;
}

// Validate registration form fields
function validateRegisterForm(form) {
  let valid = true;

  const usernameInput = form.querySelector('input[name="username"]');
  const emailInput = form.querySelector('input[name="email"]');
  const passwordInput = form.querySelector('input[name="password"]');
  const confirmInput = form.querySelector('input[name="confirmPassword"]');

  // Username validation
  if (!usernameInput.value.trim()) {
    showError(usernameInput, 'Username is required.');
    valid = false;
  } else {
    clearError(usernameInput);
  }

  // Email validation
  if (!emailInput.value.trim()) {
    showError(emailInput, 'Email is required.');
    valid = false;
  } else if (!emailRegex.test(emailInput.value.trim())) {
    showError(emailInput, 'Please enter a valid email address.');
    valid = false;
  } else {
    clearError(emailInput);
  }

  // Password validation
  if (!passwordInput.value) {
    showError(passwordInput, 'Password is required.');
    valid = false;
  } else if (passwordInput.value.length < 6) {
    showError(passwordInput, 'Password must be at least 6 characters.');
    valid = false;
  } else {
    clearError(passwordInput);
  }

  // Confirm password validation
  if (!confirmInput.value) {
    showError(confirmInput, 'Please confirm your password.');
    valid = false;
  } else if (confirmInput.value !== passwordInput.value) {
    showError(confirmInput, 'Passwords do not match.');
    valid = false;
  } else {
    clearError(confirmInput);
  }

  return valid;
}

// Attach listeners once the DOM is ready
document.addEventListener('DOMContentLoaded', () => {
  // Login form handling
  const loginForm = document.getElementById('loginForm');
  if (loginForm) {
    loginForm.addEventListener('submit', (e) => {
      if (!validateLoginForm(loginForm)) {
        e.preventDefault(); // stop submission if validation fails
      }
    });
  }

  // Registration form handling
  const registerForm = document.getElementById('registerForm');
  if (registerForm) {
    registerForm.addEventListener('submit', (e) => {
      if (!validateRegisterForm(registerForm)) {
        e.preventDefault(); // stop submission if validation fails
      }
    });
  }

  // Optional: clear errors on input change
  document.body.addEventListener('input', (e) => {
    if (e.target.matches('input')) {
      clearError(e.target);
    }
  });
});

const USERS_KEY = 'users';

/**
 * Retrieve the list of registered users from localStorage.
 * @returns {Array<{email:string,password:string,name?:string}>}
 */
function getUsers() {
  const raw = localStorage.getItem(USERS_KEY);
  try {
    return raw ? JSON.parse(raw) : [];
  } catch {
    // Corrupted data – reset to empty array
    return [];
  }
}

/**
 * Save a new user to localStorage.
 * Returns true on success, false if the email already exists or data is invalid.
 * @param {{email:string,password:string,name?:string}} user
 * @returns {boolean}
 */
function saveUser(user) {
  if (!user?.email || !user?.password) return false;

  const users = getUsers();

  // Prevent duplicate registrations
  if (users.some(u => u.email === user.email)) {
    return false;
  }

  users.push({ email: user.email, password: user.password, name: user.name });
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
  return true;
}

/**
 * Verify login credentials against stored users.
 * Returns the user object if credentials match, otherwise null.
 * @param {string} email
 * @param {string} password
 * @returns {{email:string,password:string,name?:string}|null}
 */
function verifyCredentials(email, password) {
  const users = getUsers();
  const match = users.find(u => u.email === email && u.password === password);
  return match || null;
}

// Expose functions for external use (e.g., from HTML event handlers)
window.auth = {
  getUsers,
  saveUser,
  verifyCredentials,
};

