document.addEventListener('DOMContentLoaded', () => {
  // Elements
  const loginForm = document.getElementById('login-form');
  const registerForm = document.getElementById('register-form');
  const toggleToLogin = document.getElementById('show-login');
  const toggleToRegister = document.getElementById('show-register');
  const dashboard = document.getElementById('dashboard');
  const welcomeMsg = document.getElementById('welcome-msg');
  const logoutBtn = document.getElementById('logout-btn');

  // Helper to hide all main sections
  const hideAll = () => {
    if (loginForm) loginForm.style.display = 'none';
    if (registerForm) registerForm.style.display = 'none';
    if (dashboard) dashboard.style.display = 'none';
  };

  // Show login form
  const showLogin = () => {
    hideAll();
    if (loginForm) loginForm.style.display = 'block';
  };

  // Show register form
  const showRegister = () => {
    hideAll();
    if (registerForm) registerForm.style.display = 'block';
  };

  // Show dashboard with welcome message
  const showDashboard = (username) => {
    hideAll();
    if (dashboard) {
      dashboard.style.display = 'block';
      if (welcomeMsg) welcomeMsg.textContent = `Welcome, ${username}!`;
    }
  };

  // Logout handler
  const logout = () => {
    sessionStorage.removeItem('user');
    showLogin();
  };

  // Attach toggle listeners
  if (toggleToLogin) toggleToLogin.addEventListener('click', (e) => {
    e.preventDefault();
    showLogin();
  });

  if (toggleToRegister) toggleToRegister.addEventListener('click', (e) => {
    e.preventDefault();
    showRegister();
  });

  // Login form submission
  if (loginForm) {
    loginForm.addEventListener('submit', (e) => {
      e.preventDefault();
      const formData = new FormData(loginForm);
      const username = formData.get('username')?.trim() || '';
      const password = formData.get('password')?.trim() || '';

      if (!username || !password) {
        alert('Please fill in both username and password.');
        return;
      }

      // In a real app, you'd verify credentials here.
      // For demo purposes, accept any non‑empty credentials.
      const user = { username };
      sessionStorage.setItem('user', JSON.stringify(user));
      showDashboard(username);
    });
  }

  // Register form submission
  if (registerForm) {
    registerForm.addEventListener('submit', (e) => {
      e.preventDefault();
      const formData = new FormData(registerForm);
      const username = formData.get('username')?.trim() || '';
      const password = formData.get('password')?.trim() || '';
      const confirm = formData.get('confirm')?.trim() || '';

      if (!username || !password || !confirm) {
        alert('Please fill in all fields.');
        return;
      }
      if (password !== confirm) {
        alert('Passwords do not match.');
        return;
      }

      // Simulate successful registration and auto‑login.
      const user = { username };
      sessionStorage.setItem('user', JSON.stringify(user));
      showDashboard(username);
    });
  }

  // Logout button
  if (logoutBtn) {
    logoutBtn.addEventListener('click', (e) => {
      e.preventDefault();
      logout();
    });
  }

  // Initial load: check auth state
  const stored = sessionStorage.getItem('user');
  if (stored) {
    try {
      const { username } = JSON.parse(stored);
      if (username) {
        showDashboard(username);
        return;
      }
    } catch (_) {
      // ignore parse errors
    }
  }
  // Default view
  showLogin();
});

