type DateInput = Date | string | number;

/**
 * Formats a date according to the provided locale and options.
 *
 * @param date   - The date to format. Accepts a Date instance, ISO string, or timestamp.
 * @param locale - BCP 47 language tag (e.g., "en-US", "fr-FR").
 * @param opts   - Intl.DateTimeFormat options. Defaults to a readable short format.
 *
 * @returns A locale‑aware formatted date string.
 */
export function formatDate(
  date: DateInput,
  locale: string = 'en-US',
  opts?: Intl.DateTimeFormatOptions
): string {
  const d = date instanceof Date ? date : new Date(date);
  if (isNaN(d.getTime())) {
    return '';
  }

  const defaultOpts: Intl.DateTimeFormatOptions = {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
  };

  return new Intl.DateTimeFormat(locale, { ...defaultOpts, ...opts }).format(d);
}

/**
 * Formats a number according to the provided locale and options.
 *
 * @param value  - The number to format.
 * @param locale - BCP 47 language tag.
 * @param opts   - Intl.NumberFormat options.
 *
 * @returns A locale‑aware formatted number string.
 */
export function formatNumber(
  value: number,
  locale: string = 'en-US',
  opts?: Intl.NumberFormatOptions
): string {
  if (typeof value !== 'number' || isNaN(value)) {
    return '';
  }

  const defaultOpts: Intl.NumberFormatOptions = {
    maximumFractionDigits: 2,
  };

  return new Intl.NumberFormat(locale, { ...defaultOpts, ...opts }).format(value);
}

/**
 * Formats a number as a currency string.
 *
 * @param value        - The monetary amount.
 * @param currencyCode - ISO 4217 currency code (e.g., "USD", "EUR").
 * @param locale       - BCP 47 language tag.
 * @param opts         - Additional Intl.NumberFormat options.
 *
 * @returns A formatted currency string.
 */
export function formatCurrency(
  value: number,
  currencyCode: string = 'USD',
  locale: string = 'en-US',
  opts?: Intl.NumberFormatOptions
): string {
  return formatNumber(value, locale, {
    style: 'currency',
    currency: currencyCode,
    ...opts,
  });
}

/**
 * Formats a phone number into a human‑readable form.
 *
 * This implementation is intentionally simple and works for North American
 * numbers (10‑digit) and international numbers prefixed with '+'.
 *
 * @param raw - The raw phone number string (may contain spaces, dashes, etc.).
 *
 * @returns A formatted phone number or the original string if it cannot be parsed.
 */
export function formatPhoneNumber(raw: string): string {
  const digits = raw.replace(/[^\d+]/g, '');

  // International format (starts with '+')
  if (digits.startsWith('+')) {
    return digits;
  }

  // North American format (10 digits)
  if (digits.length === 10) {
    const area = digits.slice(0, 3);
    const prefix = digits.slice(3, 6);
    const line = digits.slice(6);
    return `(${area}) ${prefix}-${line}`;
  }

  // Fallback – return cleaned digits
  return digits;
}

/**
 * Truncates a string to a maximum length, optionally adding an ellipsis.
 *
 * @param str        - The string to truncate.
 * @param maxLength  - Maximum length of the result (including ellipsis if used).
 * @param ellipsis   - Whether to append "…" when truncation occurs (default true).
 *
 * @returns The possibly truncated string.
 */
export function truncate(
  str: string,
  maxLength: number,
  ellipsis: boolean = true
): string {
  if (maxLength <= 0) return '';
  if (str.length <= maxLength) return str;

  const suffix = ellipsis ? '…' : '';
  const cutLength = maxLength - suffix.length;
  if (cutLength <= 0) return suffix.slice(0, maxLength);

  return str.slice(0, cutLength) + suffix;
}

/**
 * Formats a file size (in bytes) into a human‑readable string.
 *
 * @param bytes   - Number of bytes.
 * @param decimals - Number of decimal places (default 1).
 *
 * @returns Human‑readable file size (e.g., "1.5 MB").
 */
export function formatFileSize(bytes: number, decimals: number = 1): string {
  if (bytes < 0 || isNaN(bytes)) return '';

  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB'];
  let i = 0;
  let value = bytes;

  while (value >= 1024 && i < units.length - 1) {
    value /= 1024;
    i++;
  }

  return `${value.toFixed(decimals)} ${units[i]}`;
}

