/**
 * Formats a `Date` object into a string using the provided format.
 *
 * @param date - The date to format. If omitted, the current date/time is used.
 * @param options - Intl.DateTimeFormat options or a custom format string.
 * @returns A formatted date string.
 *
 * @example
 *   formatDate(new Date(), { year: 'numeric', month: '2-digit', day: '2-digit' });
 *   // => "2024-03-15"
 */
export function formatDate(
  date: Date = new Date(),
  options: Intl.DateTimeFormatOptions | string = {}
): string {
  if (typeof options === 'string') {
    // Simple custom format handling (YYYY, MM, DD, hh, mm, ss)
    const map: Record<string, string> = {
      YYYY: date.getFullYear().toString(),
      MM: String(date.getMonth() + 1).padStart(2, '0'),
      DD: String(date.getDate()).padStart(2, '0'),
      hh: String(date.getHours()).padStart(2, '0'),
      mm: String(date.getMinutes()).padStart(2, '0'),
      ss: String(date.getSeconds()).padStart(2, '0')
    };
    return options.replace(/YYYY|MM|DD|hh|mm|ss/g, (match) => map[match]);
  }

  return new Intl.DateTimeFormat(undefined, options).format(date);
}

/**
 * Formats a number according to the given locale and options.
